/// Maglev — multi-cloud Kubernetes cluster manager
#[derive(Parser)]
#[command(
    name = "maglev",
    version,
    about = "Provision and manage cloud-backed Kubernetes clusters"
)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Create VM instances described by a provider YAML config
    Apply {
        /// Path to the YAML config file (gcp.yaml or digitalocean.yaml)
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Permanently delete VM instances described by a provider YAML config
    Destroy {
        /// Path to the YAML config file
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Provision Kubernetes on control-plane nodes and join workers
    Play {
        /// Path to the YAML config file
        #[arg(default_value = "config/gcp.yaml")]
        config: String,
    },
    /// Run the interactive GCP credential builder
    Print,
}

// ---------------------------------------------------------------------------
// ip-address field type
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy, PartialEq, serde::Deserialize, serde::Serialize)]
#[serde(rename_all = "lowercase", deny_unknown_fields)]
enum IpAddressType {
    Public,
    Private,
}

impl Default for IpAddressType {
    fn default() -> Self {
        IpAddressType::Private
    }
}

impl fmt::Display for IpAddressType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            IpAddressType::Public => write!(f, "public"),
            IpAddressType::Private => write!(f, "private"),
        }
    }
}

// ---------------------------------------------------------------------------
// YAML types
// ---------------------------------------------------------------------------

/// A named node group with a role type (`control-plane` or `worker`).
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct GroupYaml {
    name: String,
    /// Role type — used by rules to select all groups of the same kind.
    /// Accepted values: `"control-plane"`, `"worker"`.
    #[serde(rename = "type", default)]
    group_type: String,
    node: Vec<String>,
}

/// A named spec whose config entries may supply any subset of the available
/// fields.  Multiple specs listed in a rule are merged left-to-right (later
/// entries override earlier ones for any field they define).
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct SpecYaml {
    name: String,
    /// Accepts either a YAML sequence (`- key: val`) or a bare mapping
    /// (`key: val`) — both are normalised into a `Vec<SpecConfigYaml>`.
    #[serde(deserialize_with = "deserialize_spec_config_list")]
    config: Vec<SpecConfigYaml>,
}

/// One element inside a spec's `config` list.  Every field is optional so
/// that "partial" specs (e.g. one that only sets `boot-disk-size`) can be
/// composed with others that carry the remaining fields.
#[derive(Debug, Default, Clone, serde::Deserialize, serde::Serialize)]
struct SpecConfigYaml {
    #[serde(default, skip_serializing_if = "Option::is_none")]
    script: Option<String>,
    #[serde(rename = "ssh-public-key", default, skip_serializing_if = "Option::is_none")]
    ssh_public_key: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    user: Option<String>,
    #[serde(rename = "machine-type", default, skip_serializing_if = "Option::is_none")]
    machine_type: Option<String>,
    #[serde(rename = "boot-disk-image", default, skip_serializing_if = "Option::is_none")]
    boot_disk_image: Option<String>,
    #[serde(rename = "boot-disk-size", default, skip_serializing_if = "Option::is_none")]
    boot_disk_size: Option<u64>,
    #[serde(rename = "ip-address", default, skip_serializing_if = "Option::is_none")]
    ip_address: Option<IpAddressType>,
    #[serde(rename = "control-plane-endpoint", default, skip_serializing_if = "Option::is_none")]
    control_plane_endpoint: Option<String>,
}

/// A rule binds all groups of a given `type` to an ordered list of spec
/// names.  The specs are merged in order to produce a single resolved config.
#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct RuleYaml {
    /// Matches `group[].type`, not `group[].name`.
    group: String,
    /// Ordered list of spec names.  Fields defined in later specs override
    /// those from earlier ones.
    specs: Vec<String>,
}

// ---------------------------------------------------------------------------
// Custom deserialiser: accept either a sequence or a bare mapping for
// `SpecYaml.config`.
// ---------------------------------------------------------------------------

fn deserialize_spec_config_list<'de, D>(d: D) -> Result<Vec<SpecConfigYaml>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    use serde::de::{self, MapAccess, SeqAccess, Visitor};

    struct SpecConfigVisitor;

    impl<'de> Visitor<'de> for SpecConfigVisitor {
        type Value = Vec<SpecConfigYaml>;

        fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
            f.write_str("a mapping or a sequence of spec-config mappings")
        }

        fn visit_seq<A: SeqAccess<'de>>(self, mut seq: A) -> Result<Self::Value, A::Error> {
            let mut out = Vec::new();
            while let Some(item) = seq.next_element::<SpecConfigYaml>()? {
                out.push(item);
            }
            Ok(out)
        }

        fn visit_map<A: MapAccess<'de>>(self, map: A) -> Result<Self::Value, A::Error> {
            let item =
                SpecConfigYaml::deserialize(de::value::MapAccessDeserializer::new(map))?;
            Ok(vec![item])
        }
    }

    d.deserialize_any(SpecConfigVisitor)
}

// ---------------------------------------------------------------------------
// Fully-resolved (merged) configuration for one rule
// ---------------------------------------------------------------------------

/// The result of merging all specs listed by a rule.
///
/// Every field that is required for VM creation must have been supplied by at
/// least one of the merged specs; otherwise `merge_specs` returns an error.
#[derive(Debug, Clone)]
struct MergedConfig {
    script: String,
    ssh_public_key: String,
    user: String,
    machine_type: String,
    boot_disk_image: String,
    boot_disk_size: u64,
    ip_address: IpAddressType,
    control_plane_endpoint: Option<String>,
}

/// Merge a list of `SpecConfigYaml` entries (already looked up by name) into
/// a single `MergedConfig`.  Fields from later entries override earlier ones.
fn merge_spec_configs(
    spec_names: &[String],
    specs_map: &HashMap<&str, &SpecYaml>,
) -> Result<MergedConfig, Box<dyn std::error::Error>> {
    let mut acc = SpecConfigYaml::default();

    for name in spec_names {
        let spec_yaml = specs_map
            .get(name.as_str())
            .ok_or_else(|| format!("Unknown spec '{name}'"))?;

        // Take the first config entry — subsequent entries within the same
        // spec are not used (spec composition is done at the rule level).
        let cfg = spec_yaml
            .config
            .first()
            .ok_or_else(|| format!("Spec '{name}' has an empty config list"))?;

        if let Some(v) = &cfg.script {
            acc.script = Some(v.clone());
        }
        if let Some(v) = &cfg.ssh_public_key {
            acc.ssh_public_key = Some(v.clone());
        }
        if let Some(v) = &cfg.user {
            acc.user = Some(v.clone());
        }
        if let Some(v) = &cfg.machine_type {
            acc.machine_type = Some(v.clone());
        }
        if let Some(v) = &cfg.boot_disk_image {
            acc.boot_disk_image = Some(v.clone());
        }
        if let Some(v) = cfg.boot_disk_size {
            acc.boot_disk_size = Some(v);
        }
        if let Some(v) = cfg.ip_address {
            acc.ip_address = Some(v);
        }
        if let Some(v) = &cfg.control_plane_endpoint {
            acc.control_plane_endpoint = Some(v.clone());
        }
    }

    Ok(MergedConfig {
        script: acc.script.unwrap_or_default(),
        ssh_public_key: acc.ssh_public_key.unwrap_or_default(),
        user: acc.user.unwrap_or_default(),
        machine_type: acc
            .machine_type
            .ok_or_else(|| format!("No 'machine-type' found after merging specs {spec_names:?}"))?,
        boot_disk_image: acc.boot_disk_image.ok_or_else(|| {
            format!("No 'boot-disk-image' found after merging specs {spec_names:?}")
        })?,
        boot_disk_size: acc.boot_disk_size.unwrap_or(20),
        ip_address: acc.ip_address.unwrap_or_default(),
        control_plane_endpoint: acc.control_plane_endpoint,
    })
}

// ---------------------------------------------------------------------------
// Provider-specific credential types
// ---------------------------------------------------------------------------

#[derive(Debug, serde::Deserialize, serde::Serialize)]
struct GcpCredentialsYaml {
    #[serde(rename = "client-email")]
    client_email: String,
    #[serde(rename = "private-key")]
    private_key: String,
    #[serde(rename = "project-id")]
    project_id: String,
